import math
from collections import deque

class TreeNode:
  def __init__(self, val):
    self.data = val
    self.left = None
    self.right = None

def checkEmptySubtree(index, arr, n, visited_empty_nodes):
  if arr[index] != -1:
    return False

  visited_empty_nodes.add(index)

  left_index = 2*index + 1
  right_index = 2*index + 2
  left, right = True, True

  if left_index < n:
    left = checkEmptySubtree(left_index, arr, n, visited_empty_nodes)

  if right_index < n:
    right = checkEmptySubtree(right_index, arr, n, visited_empty_nodes)

  return right and left


def isValidBinaryArr(arr, n):
  number_of_levels = math.log(n+1, 2)
  if number_of_levels != int(number_of_levels):
    return False

  null_nodes = []
  visited_empty_nodes = set()
  for i in range(n):
    if arr[i] == -1 and i not in visited_empty_nodes:
      ans = checkEmptySubtree(i, arr, n, visited_empty_nodes)
      if not ans:
        return False

  return True


def buildBinaryTree(arr):
  n = len(arr)
  if not isValidBinaryArr(arr, n):
    return "invalid"

  if n==1:
    if arr[0]==-1:
      return []
    return arr[0]

  root = TreeNode(arr[0])
  dq = deque()
  dq.append((root, 0))
  while dq:
    size = len(dq)
    for i in range(size):
      temp = dq.popleft()
      node, index = temp
      left = 2*index+1
      right = 2*index+2
      if  left< n and arr[left] != -1:
        node.left = TreeNode(arr[left])
        dq.append((node.left, left))

      if right<n and arr[right] != -1:
        node.right = TreeNode(arr[right])
        dq.append((node.right, right))

  return root

